import React, { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import Navbar from "../components/Navbar";

function Landing() {
  const navigate = useNavigate();

  useEffect(() => {
    document.body.style.overflow = "hidden";
    return () => (document.body.style.overflow = "auto");
  }, []);

  const handleContinue = () => {
    localStorage.removeItem("role");
    navigate("/login");
  };

  return (
    <div className="landing-page">
      <Navbar />

      {/* HERO SECTION */}
      <section className="hero-section">
        <div className="hero-overlay" />

        <div className="hero-content">
          <span className="hero-badge">
            AI-powered Retail Intelligence
          </span>

          <h1 className="hero-title">
            Welcome to <span className="heading">RetailVision</span>
          </h1>

          <p className="hero-subtitle">
            Smarter inventory. Clearer decisions.
          </p>

          <p className="hero-description">
            Forecast demand, optimize stock, and gain actionable insights —
            all from a single intelligent dashboard built for modern retailers.
          </p>

          {/* CTA */}
          <div className="hero-cta">
            <button
              className="btn-primary"
              onClick={handleContinue}
            >
              Continue to Login
            </button>

            <button
              className="btn-secondary"
              onClick={() => navigate("/signup")}
            >
              Create Account
            </button>
          </div>

          {/* TRUST STRIP */}
          <div className="hero-metrics">
            <div>
              <strong>30%</strong>
              <span>Less Stock Waste</span>
            </div>
            <div>
              <strong>2×</strong>
              <span>Faster Decisions</span>
            </div>
            <div>
              <strong>AI</strong>
              <span>Sales Suggestions</span>
            </div>
          </div>
        </div>
      </section>

      {/* FOOTER */}
      <footer className="footer">
        © 2026 RetailVision • Privacy • Terms
      </footer>
    </div>
  );
}

export default Landing;
